parameters.jsCode:
const webhookCtx = $('Apify webhook').first().json.body;
const __all = $input.all();
let placesArr;
if (__all.length === 1 && Array.isArray(__all[0].json)) { placesArr = __all[0].json; }
else if (__all.length === 1 && __all[0].json && Array.isArray(__all[0].json.body)) { placesArr = __all[0].json.body; }
else { placesArr = __all.map(function (i) { return i.json; }); }

// Trim common company suffixes so you get a clean short name for outreach
// ("Smith & Co" not "Smith & Co., LLC"). Add your own patterns as needed.
const SUFFIX_PATTERNS = [
  /,?\s+&\s+Associates\.?\b/gi,
  /,?\s+L\.?L\.?C\.?\b/gi,
  /,?\s+L\.?L\.?P\.?\b/gi,
  /,?\s+P\.?L\.?L\.?C\.?\b/gi,
  /,?\s+P\.?C\.?\b/gi,
  /,?\s+Inc\.?\b/gi,
  /,?\s+Corp\.?\b/gi,
  /,?\s+Co\.?\b/gi,
  /,?\s+Ltd\.?\b/gi,
  /,?\s+Group\b/gi,
  /,?\s+Holdings\b/gi,
  /^The\s+/gi,
];
function shorten(name) {
  if (!name) return null;
  let s = String(name).trim();
  let changed = true;
  while (changed) {
    changed = false;
    for (const pat of SUFFIX_PATTERNS) {
      const next = s.replace(pat, '').replace(/[\s,.]+$/, '').replace(/^[\s,.]+/, '');
      if (next && next !== s) { s = next; changed = true; }
    }
  }
  return s || String(name).trim();
}
function canonicalDomain(url) {
  if (!url) return null;
  try {
    const u = new URL(String(url).trim().startsWith('http') ? url : 'http://' + url);
    return u.hostname.toLowerCase().replace(/^www\./, '') || null;
  } catch (e) {
    return String(url).toLowerCase().replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0] || null;
  }
}
return placesArr.map((p) => {
  const website = p.website || p.url || null;
  const domain = canonicalDomain(website);
  return {
    json: {
      run_pk: webhookCtx.run_pk,
      vertical: webhookCtx.vertical,
      apify_run_id: webhookCtx.apify_run_id,
      place_id: p.placeId || p.place_id || null,
      canonical_domain: domain,
      firm_name: p.title || p.name || null,
      firm_short_name: shorten(p.title || p.name),
      website: website,
      phone: p.phone || p.phoneUnformatted || null,
      email: (p.emails && p.emails[0]) || null,
      address: p.address || null,
      city: p.city || null,
      state: p.state || null,
      postal_code: p.postalCode || null,
      category: p.categoryName || (p.categories && p.categories[0]) || null,
      rating: p.totalScore || null,
      reviews_count: p.reviewsCount || null,
      permanently_closed: !!p.permanentlyClosed,
      raw_payload: p,
    },
  };
});

// ---- EDIT THIS BLOCK: your Ideal Customer Profile -------------------
// Google Maps + Apollo hand you these signals for free. Tune them to
// describe YOUR ideal customer; the reveal gate then only spends a
// credit on businesses that clear the bar.
const TARGET_STATES   = ['NY', 'NJ', 'CT'];                 // states/regions you sell into; [] disables the geo signal
const TARGET_CATEGORY = /(consult|agency|studio|service)/i; // words in the Google category that signal a fit
const MIN_RATING      = 4.0;                                // Google rating floor
const MIN_REVIEWS     = 50;                                 // review-count floor (proxy for an established business)
// --------------------------------------------------------------------

function scoreLead(o) {
  let score = 0; const reasons = {};
  if (o.rating != null && Number(o.rating) >= MIN_RATING) { score += 20; reasons.rating = Number(o.rating); }
  if (o.reviews_count != null && Number(o.reviews_count) >= MIN_REVIEWS) { score += 20; reasons.reviews = Number(o.reviews_count); }
  if (o.website) { score += 20; reasons.has_website = true; }
  if (o.state && (TARGET_STATES.length === 0 || TARGET_STATES.includes(String(o.state).toUpperCase().trim()))) { score += 20; reasons.in_region = o.state || 'any'; }
  if (o.category && TARGET_CATEGORY.test(o.category)) { score += 20; reasons.category_match = o.category; }
  return { score: Math.min(score, 100), reasons };
}

const runPk = $('Apify webhook').first().json.body.run_pk;
const items = $input.all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const peopleResp = items[i].json || {};
  let raw = {}, orgResp = {};
  try { raw = $('Insert raw').itemMatching(i).json; } catch (e) { try { raw = $('Insert raw').all()[i].json; } catch (e2) {} }
  try { orgResp = $('Apollo: enrich org (free)').itemMatching(i).json; } catch (e) { try { orgResp = $('Apollo: enrich org (free)').all()[i].json; } catch (e2) {} }

  const org = (orgResp && (orgResp.organization || (orgResp.organizations && orgResp.organizations[0]))) || {};
  const people = (org && org.id) ? (peopleResp.people || peopleResp.contacts || []) : [];
  const employees = org.estimated_num_employees || org.employees_count || null;
  const industry = org.industry || (org.industries && org.industries[0]) || null;
  const category = raw.category || industry || null;

  const s = scoreLead({ rating: raw.rating, reviews_count: raw.reviews_count, website: raw.website, state: raw.state, category: category });

  const base = {
    raw_id: raw.id, run_id: runPk, canonical_domain: raw.canonical_domain,
    firm_name: raw.firm_name, firm_short_name: raw.firm_short_name,
    apollo_org_id: org.id || null, employee_count: employees, industry: industry,
    practice_area: category, linkedin_url: org.linkedin_url || null, apollo_org_payload: org,
  };

  if (!people.length) {
    out.push({ json: Object.assign({}, base, { apollo_person_id: null, first_name: null, last_name: null, title: null, seniority: null, email: null, email_status: 'no_contact_found', phone: null, person_linkedin_url: null, icp_score: s.score, icp_reasons: Object.assign({}, s.reasons, { reason: 'no_apollo_people_match' }), apollo_person_payload: null }), pairedItem: { item: i } });
  } else {
    for (const person of people) {
      out.push({ json: Object.assign({}, base, { apollo_person_id: person.id || null, first_name: person.first_name || null, last_name: person.last_name || person.last_name_obfuscated || null, title: person.title || null, seniority: person.seniority || null, email: null, email_status: 'unrevealed', phone: (person.phone_numbers && person.phone_numbers[0] && person.phone_numbers[0].sanitized_number) || null, person_linkedin_url: person.linkedin_url || null, icp_score: s.score, icp_reasons: s.reasons, apollo_person_payload: person }), pairedItem: { item: i } });
    }
  }
}
return out;

// Decide reveals across ALL enriched contacts in this batch, with a running
// within-batch counter so we never exceed the monthly cap.
const enrichedRows = $('Insert enriched').all();
const budgetRows = $input.all();
const b0 = budgetRows[0].json;
const cap = Number(b0.reveals_cap || 0);
const minScore = Number(b0.min_score || 60);
let used = Number(b0.reveals_used || 0);

const TITLE_REGEX = /(owner|president|ceo|chief executive|founder|co-founder|principal|managing partner|founding partner|senior partner|partner|managing director|general manager|vice president|operations manager|managing member)/i;

return enrichedRows.map((row, i) => {
  const enriched = row.json;
  const score = Number(enriched.icp_score || 0);
  const title = enriched.title || '';
  const apolloPersonId = enriched.apollo_person_id;
  const shouldReveal = apolloPersonId && used < cap && score >= minScore && TITLE_REGEX.test(title);
  if (shouldReveal) used += 1;
  return {
    json: {
      ...enriched,
      should_reveal: !!shouldReveal,
      reveals_used: used,
      reveals_remaining: Math.max(0, cap - used),
      reveal_skip_reason: shouldReveal ? null :
        (!apolloPersonId ? 'no_apollo_id'
          : used >= cap ? 'monthly_cap_exhausted'
          : score < minScore ? `score_below_${minScore}`
          : 'title_not_partner_level'),
    },
    pairedItem: { item: i },
  };
});

parameters.query:
UPDATE cold_outreach.gms_leads_enriched
SET icp_reasons = icp_reasons || jsonb_build_object('reveal_skipped', $1)
WHERE id = $2;

UPDATE cold_outreach.gms_leads_raw
SET enrichment_status = 'enriched'
WHERE run_id = $1 AND enrichment_status IS DISTINCT FROM 'enriched';

UPDATE cold_outreach.gms_leads_raw
SET enrichment_status = 'skipped', enrichment_error = 'no_canonical_domain'
WHERE id = $1;
